+ (void)presentVipPageFromPageSource:(NSString *)pageSource {
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];

    if ([rootVC isKindOfClass:[WBMainViewController class]]) {
        WBMainViewController *mainVC = (WBMainViewController *)rootVC;
        [mainVC presentVipPagePrivateFromPageSource:pageSource triggerId:nil];
    }
}

