        self.payOptionsView.userInteractionEnabled = YES;
        self.purchaseView.userInteractionEnabled = YES;
    } else {    // 当前展示货架无商品，禁止商品相关交互
        self.promoSectionView.userInteractionEnabled = NO;
        self.payOptionsView.userInteractionEnabled = NO;
        self.purchaseView.userInteractionEnabled = NO;
    }
}


#pragma mark - Actions

- (void)returnButtonClicked {
    [[NSNotificationCenter defaultCenter] postNotificationName:WBVipReturnNotification object:nil];
    [WBEventManager logAppPageShowEvent:@"Vip" from:@"close"];
    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypePageVipClosing defaultHandler:^(WBBaseActionModel * _Nullable actionModel) {
        if (!actionModel) {
            [self handleActionRequestErrorWhenReturn];
        }
        [self handleNormalReturnAndDismissAction];
    }];
}

- (void)handleActionRequestErrorWhenReturn {
//    [WBProgressHUD showPlainNetworkError];
}

- (void)handleNormalReturnAndDismissAction {
    //    [self.navigationController dismissViewControllerAnimated:YES completion:nil];
    if ([self.navigationController respondsToSelector:@selector(pushViewController:animated:)]) {
        [self.navigationController popToRootViewControllerAnimated:true];
    }
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [self.navigationController dismissViewControllerAnimated:YES completion:^{
            if (self.dismissBlock) self.dismissBlock();
        }];
    });
}

- (void)purchaseButtonClicked {
    if (self.productCollectionView.products.count) {
        [self purchaseSelectedProduct];
    } else {
        [SVProgressHUD showErrorWithStatus:@"暂无商品，支付失败"];
    }
}
